import { type DependencyList, type Dispatch, type SetStateAction, useState } from 'react';
import { useDepsChanged } from '#registry/default/hooks/use-deps-changed.ts';
import { isFunction } from '#registry/default/lib/is-function.ts';

/**
 * This hook works like `useState`, but it takes an additional dependency list parameter to reset the state when the dependencies change.
 * It is useful when we want to reset the state when some external values change.
 */
export function useStateWithDeps<S>(
  initialState: S | (() => S),
  deps?: DependencyList
): [S, Dispatch<SetStateAction<S>>] {
  const [state, setState] = useState(initialState);

  let initialValue: S;
  if (!deps) {
    initialValue = isFunction(initialState) ? (initialState as () => S)() : initialState;
    deps = [initialValue];
  }
  const depsChanged = useDepsChanged(deps);

  if (depsChanged) {
    initialValue ??= isFunction(initialState) ? (initialState as () => S)() : initialState;
    setState(initialValue);
  }

  return [state, setState] as const;
}
